// ── HELPERS ────────────────────────────────────────────────────
function Stars({n=5}){
  return <span>{Array.from({length:n}).map((_,i)=><span key={i} style={{color:"#C9A84C"}}>★</span>)}</span>;
}
function useInView(ref,thr=0.15){
  const [v,setV]=useState(false);
  useEffect(()=>{
    const o=new IntersectionObserver(([e])=>{if(e.isIntersecting)setV(true)},{threshold:thr});
    if(ref.current)o.observe(ref.current);
    return()=>o.disconnect();
  },[ref,thr]);
  return v;
}
function Counter({target,suf=""}){
  const [val,setVal]=useState(0);
  const ref=useRef(null);
  const inV=useInView(ref);
  useEffect(()=>{
    if(!inV)return;
    let s=0;const step=target/60;
    const t=setInterval(()=>{s+=step;if(s>=target){setVal(target);clearInterval(t);}else setVal(Math.floor(s));},16);
    return()=>clearInterval(t);
  },[inV,target]);
  return <span ref={ref} style={{animation:inV?"countUp .5s ease":"none"}}>{val.toLocaleString()}{suf}</span>;
}
