// ── PRODUCT CARD ───────────────────────────────────────────────
function PCard({p,selected,onSelect,addToCart}){
  const[added,setAdded]=useState(false);
  const[qty,setQty]=useState(p.cat==="samboussa"?10:1);
  const[customMode,setCustomMode]=useState(false);
  const quickQtys=QUICK_QTY[p.cat]||[1];
  const pricing=priceFor(p.cat,qty);

  const setSafeQty=(v)=>{
    let n=parseInt(v,10);
    if(isNaN(n)||n<1)n=1;
    if(n>MAX_QTY)n=MAX_QTY;
    setQty(n);
  };

  const handleAdd=(e)=>{
    e.stopPropagation();
    addToCart(p,qty);
    setAdded(true);
    setTimeout(()=>setAdded(false),2000);
  };

  return(
    <div onClick={()=>onSelect(p.id)} style={{
      background:"#161616",
      border:selected?"1px solid #C9A84C":"1px solid rgba(201,168,76,.12)",
      borderRadius:16,overflow:"hidden",cursor:"pointer",
      transition:"all .35s cubic-bezier(.175,.885,.32,1.275)",
      transform:selected?"scale(1.025)":"scale(1)",
      animation:selected?"glow 2s ease-in-out infinite":"none",
      boxShadow:selected?"0 0 32px rgba(201,168,76,.2)":"0 4px 20px rgba(0,0,0,.3)",
    }}
      onMouseEnter={e=>{if(!selected){e.currentTarget.style.transform="translateY(-5px) scale(1.015)";e.currentTarget.style.borderColor="rgba(201,168,76,.4)";}}}
      onMouseLeave={e=>{if(!selected){e.currentTarget.style.transform="scale(1)";e.currentTarget.style.borderColor="rgba(201,168,76,.12)";}}}
    >
      {/* image */}
      <div style={{height:220,position:"relative",overflow:"hidden"}}>
        <img src={IMGS[p.img]} alt={p.name} style={{
          width:"100%",height:"100%",objectFit:"cover",
          transition:"transform .5s ease",
          transform:selected?"scale(1.08)":"scale(1)",
        }}/>
        <div style={{position:"absolute",inset:0,background:"linear-gradient(0deg,rgba(10,10,10,.7) 0%,transparent 50%)"}}/>
        {p.tag&&(
          <div style={{position:"absolute",top:12,left:12,
            background:"rgba(201,168,76,.15)",border:"1px solid rgba(201,168,76,.4)",
            color:"#C9A84C",fontSize:9,letterSpacing:1.5,padding:"3px 9px",borderRadius:20,fontWeight:600,textTransform:"uppercase"}}>
            {p.tag}
          </div>
        )}
        {selected&&<div style={{position:"absolute",top:12,right:12}}><Check/></div>}
        <div style={{position:"absolute",bottom:12,left:12}}>
          <span style={{fontSize:9,letterSpacing:2,textTransform:"uppercase",color:"rgba(245,240,232,.6)"}}>
            {p.cat==="samboussa"?"Samboussa":"Couscouma"}
          </span>
        </div>
      </div>

      {/* body */}
      <div style={{padding:"18px 20px 20px"}}>
        <p style={{color:"#C9A84C",fontSize:9,letterSpacing:2,textTransform:"uppercase",marginBottom:5}}>{p.tagline}</p>
        <h3 className="pf" style={{fontSize:20,color:"#F5F0E8",marginBottom:8,fontWeight:600}}>{p.name}</h3>
        <p style={{color:"#6B6B6B",fontSize:12.5,lineHeight:1.55,marginBottom:12}}>{p.desc}</p>

        {/* Quick qty pills */}
        <div onClick={e=>e.stopPropagation()} style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:10}}>
          {quickQtys.map(n=>{
            const t=TIERS[p.cat].find(x=>x.qty===n);
            const active=qty===n&&!customMode;
            return(
              <button key={n}
                onClick={()=>{setQty(n);setCustomMode(false);}}
                style={{
                  position:"relative",
                  padding:"7px 11px",borderRadius:8,
                  background:active?"linear-gradient(135deg,#8A6E2F,#C9A84C)":"#1F1F1F",
                  border:active?"1px solid #E8D5A3":"1px solid rgba(201,168,76,.2)",
                  color:active?"#0A0A0A":"#C9A84C",
                  fontSize:12,fontWeight:600,cursor:"pointer",
                  transition:"all .2s",
                  boxShadow:active?"0 0 12px rgba(201,168,76,.4)":"none",
                }}
                onMouseEnter={e=>{if(!active)e.currentTarget.style.borderColor="#C9A84C";}}
                onMouseLeave={e=>{if(!active)e.currentTarget.style.borderColor="rgba(201,168,76,.2)";}}>
                {n}
                {t?.offer&&!active&&<span style={{position:"absolute",top:-5,right:-5,width:7,height:7,borderRadius:"50%",background:"#E8D5A3",boxShadow:"0 0 6px #E8D5A3"}}/>}
              </button>
            );
          })}
          <button onClick={()=>setCustomMode(!customMode)} style={{
            padding:"7px 11px",borderRadius:8,
            background:customMode?"linear-gradient(135deg,#8A6E2F,#C9A84C)":"#1F1F1F",
            border:customMode?"1px solid #E8D5A3":"1px dashed rgba(201,168,76,.3)",
            color:customMode?"#0A0A0A":"#9A9A8A",
            fontSize:11,fontWeight:600,cursor:"pointer",transition:"all .2s",
          }}>
            ✎ Perso
          </button>
        </div>

        {/* Custom input */}
        {customMode&&(
          <div onClick={e=>e.stopPropagation()} style={{display:"flex",alignItems:"center",gap:8,marginBottom:10,padding:"8px 10px",background:"#0F0F0F",border:"1px solid rgba(201,168,76,.2)",borderRadius:9}}>
            <button className="qbtn" onClick={()=>setSafeQty(qty-1)}>−</button>
            <input type="number" min={1} max={MAX_QTY} value={qty}
              onChange={e=>setSafeQty(e.target.value)}
              onClick={e=>e.stopPropagation()}
              style={{padding:"5px 8px",fontSize:13,textAlign:"center",borderRadius:6,maxWidth:64}}/>
            <button className="qbtn" onClick={()=>setSafeQty(qty+1)}>+</button>
            <span style={{color:"#6B6B6B",fontSize:11,marginLeft:"auto"}}>max {MAX_QTY}</span>
          </div>
        )}

        {/* Price & savings card */}
        <div style={{
          background:"rgba(201,168,76,.05)",
          border:"1px solid rgba(201,168,76,.2)",
          borderRadius:11,padding:"12px 14px",marginBottom:12,
          position:"relative",overflow:"hidden",
        }}>
          {pricing.tier?.offer&&(
            <div style={{
              position:"absolute",top:-1,right:-1,
              background:`linear-gradient(135deg,${pricing.tier.offerColor},#8A6E2F)`,
              color:"#0A0A0A",fontSize:9,letterSpacing:1,fontWeight:700,
              padding:"3px 9px",borderBottomLeftRadius:9,textTransform:"uppercase",
            }}>{pricing.tier.offer}</div>
          )}
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"baseline",marginBottom:4}}>
            <span style={{color:"#6B6B6B",fontSize:11,letterSpacing:1,textTransform:"uppercase"}}>Total</span>
            <span className="pf gold-text" style={{fontSize:26,fontWeight:700}}>{pricing.total.toFixed(2)} €</span>
          </div>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",fontSize:11.5}}>
            <span style={{color:"#9A9A8A"}}>≈ {pricing.unit.toFixed(2)} € / pièce</span>
            {pricing.savings>0&&(
              <span style={{color:"#4ADE80",fontWeight:600,display:"flex",alignItems:"center",gap:4}}>
                💰 −{pricing.savings.toFixed(2)} €
              </span>
            )}
          </div>
          {pricing.nextTier&&pricing.savings<((pricing.nextTier.qty*TIERS[p.cat][0].price)-pricing.nextTier.price)&&(
            <p style={{color:"#C9A84C",fontSize:10.5,marginTop:6,lineHeight:1.4}}>
              ✨ Passez à <strong>{pricing.nextTier.qty}</strong> pour économiser encore plus !
            </p>
          )}
        </div>

        {/* Add to cart */}
        <button className="btn-g" onClick={handleAdd} style={{width:"100%",padding:"13px",borderRadius:10,fontSize:11,display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>
          {added?<><Check/><span>Ajouté !</span></>:<><span>🛒</span><span>Ajouter au panier</span></>}
        </button>

        {/* Delivery hint */}
        <p style={{color:"#6B6B6B",fontSize:10.5,textAlign:"center",marginTop:10,display:"flex",alignItems:"center",justifyContent:"center",gap:5,lineHeight:1.4}}>
          <span>❄️</span><span>Livrés non cuits, prêts à congeler dès réception.</span>
        </p>
      </div>
    </div>
  );
}

// ── PAGE: NOS PRODUITS ─────────────────────────────────────────
