// ── APP ────────────────────────────────────────────────────────
export default function App(){
  const[page,setPage]=useState("Accueil");
  const[cart,setCart]=useState([]);
  const[cartOpen,setCartOpen]=useState(false);
  const cartCount=cart.reduce((s,i)=>s+i.qty,0);

  const addToCart=(product,qty=1)=>{
    setCart(prev=>{
      const ex=prev.find(i=>i.id===product.id);
      if(ex)return prev.map(i=>i.id===product.id?{...i,qty:Math.min(MAX_QTY,i.qty+qty)}:i);
      return[...prev,{...product,qty:Math.min(MAX_QTY,qty)}];
    });
  };

  const renderPage=()=>{
    switch(page){
      case "Accueil": return <><Hero setPage={setPage}/><Stats/><PacksSection setPage={setPage}/><MarseilleSection/><DeliverySection/><PhoneSection/><SnapchatSection/><ProductsPage addToCart={addToCart}/><Reviews/></>;
      case "Nos Produits": return <ProductsPage addToCart={addToCart}/>;
      case "Tarifs": return <TarifsPage setPage={setPage}/>;
      case "Commander": return <CommandePage cart={cart} setCart={setCart}/>;
      case "Contact": return <ContactPage/>;
      case "À Propos": return <AboutPage/>;
      default: return <><Hero setPage={setPage}/><Stats/><PacksSection setPage={setPage}/><MarseilleSection/><DeliverySection/><PhoneSection/><SnapchatSection/><ProductsPage addToCart={addToCart}/><Reviews/></>;
    }
  };

  return(
    <>
      <style dangerouslySetInnerHTML={{__html:CSS}}/>
      <AnnouncementBanner/>
      <Navbar page={page} setPage={setPage} cartCount={cartCount} setCartOpen={setCartOpen}/>
      <main style={{paddingTop:0}}>{renderPage()}</main>
      <Footer setPage={setPage}/>
      {cartOpen&&<CartPanel cart={cart} setCart={setCart} onClose={()=>setCartOpen(false)} setPage={setPage}/>}
    </>
  );
}
